from json_populate_recordset(null::"public"."progression_conditions", $seed_progression_conditions$[{"id":"d8f4206e-184e-4b21-9e04-000eac8ff8ca","code":"condition_first_seed_together","title":"Primera semilla sembrada juntos","description":"Se activa cuando existe al menos una semilla creada en el jardin.","template_id":"first_seed_together","narrative_seed":"dar una recompensa muy temprana para que el sistema responda pronto y se entienda","enabled":true,"created_at":"2026-04-07T14:18:30.640Z","updated_at":"2026-04-07T14:51:09.352Z"},{"id":"c22a6cb6-9f71-4f80-91e7-4231a2a8520d","code":"condition_first_water_family_plan","title":"Primera experiencia de agua","description":"Se activa cuando aparece al menos una pagina de esa familia y ademas esa pagina tiene algo de relato.","template_id":"first_water_family_plan","narrative_seed":"hacer visible la variedad del jardin sin regalar ramas vacias por un dato muy pobre","enabled":true,"created_at":"2026-04-07T14:18:30.640Z","updated_at":"2026-04-07T14:51:09.352Z"},{"id":"941d89e2-8f30-4351-b03e-4d6e8c2f4721","code":"condition_first_fire_family_plan","title":"Primera experiencia de fuego","description":"Se activa cuando aparece al menos una pagina de esa familia y ademas esa pagina tiene algo de relato.","template_id":"first_fire_family_plan","narrative_seed":"hacer visible la variedad del jardin sin regalar ramas vacias por un dato muy pobre","enabled":true,"created_at":"2026-04-07T14:18:30.640Z","updated_at":"2026-04-07T14:51:09.352Z"},{"id":"7415265b-7d48-4c77-a0b6-422eedecbbb1","code":"condition_first_earth_family_plan","title":"Primera experiencia de tierra","description":"Se activa cuando aparece al menos una pagina de esa familia y ademas esa pagina tiene algo de relato.","template_id":"first_earth_family_plan","narrative_seed":"hacer visible la variedad del jardin sin regalar ramas vacias por un dato muy pobre","enabled":true,"created_at":"2026-04-07T14:18:30.640Z","updated_at":"2026-04-07T14:51:09.352Z"},{"id":"dc